        raise ApiError(413, [{"field": "body", "code": "too_large", "message": "Request body is too large."}])

    ctype = request.headers.get("content-type", "")
    if "application/json" not in ctype.lower():
        raise ApiError(415, [{"field": "body", "code": "unsupported_media_type", "message": "Use application/json."}])

    allowed = {o.strip() for o in os.getenv("ALLOWED_ORIGINS", "").split(",") if o.strip()}
    origin = request.headers.get("origin")
    if allowed and origin and origin not in allowed:
        raise ApiError(403, [{"field": "request", "code": "bad_origin", "message": "Origin is not allowed."}])

    if request.headers.get("cookie"):
        header_token = request.headers.get("x-csrf-token", "")
        cookie_token = request.cookies.get("csrf_token", "")
        if not header_token or not cookie_token or not hmac.compare_digest(header_token, cookie_token):
