def has_unsafe_unicode(s: str) -> bool:
    return any(unicodedata.category(ch) in {"Cc", "Cf", "Cs", "Co", "Cn"} for ch in s)


def skeletonize(s: str) -> str:
    return re.sub(r"[^a-z0-9]", "", s.casefold().translate(LEET))


def domain_matches(domain: str, blocked: set[str]) -> bool:
