def validate_email_field(value: Any, errors: list[dict[str, str]]) -> dict[str, str] | None:
    if not isinstance(value, str):
        err(errors, "email", "invalid_type", "Email must be a string.")
        return None

    raw = unicodedata.normalize("NFKC", value.strip())
    if not raw:
        err(errors, "email", "required", "Email is required.")
        return None
    if len(raw) > 320 or len(raw.encode("utf-8")) > 512:
        err(errors, "email", "too_long", "Email is too long.")
        return None
    if has_unsafe_unicode(raw) or any(ch.isspace() for ch in raw):
        err(errors, "email", "unsafe_characters", "Email contains unsafe characters or whitespace.")
        return None

    try:
        info = validate_email(raw, check_deliverability=CHECK_EMAIL_DELIVERABILITY, allow_smtputf8=False)
        ascii_email = getattr(info, "ascii_email", None) or info.normalized
        local, domain = ascii_email.rsplit("@", 1)
        domain = idna.encode(domain, uts46=True).decode("ascii").lower()
        canonical = f"{local.lower()}@{domain}"
    except (EmailNotValidError, idna.IDNAError, ValueError) as exc:
        err(errors, "email", "invalid_format", f"Email is invalid: {exc}")
        return None

    if len(canonical) > 254 or len(local) > 64 or len(domain) > 253:
        err(errors, "email", "too_long", "Email exceeds RFC length limits.")
    if "." not in domain or domain.endswith((".local", ".localhost", ".test", ".invalid", ".example", ".internal", ".lan")):
        err(errors, "email", "invalid_domain", "Email domain must be a public domain.")
    if domain_matches(domain, DISPOSABLE_DOMAINS):
        err(errors, "email", "disposable_domain", "Disposable email domains are not allowed.")
    try:
        ipaddress.ip_address(domain.strip("[]"))
        err(errors, "email", "ip_literal_domain", "Email domain cannot be an IP address.")
    except ValueError:
        pass

    return {"email": canonical, "email_domain": domain}


def validate_username(value: Any, errors: list[dict[str, str]]) -> dict[str, str] | None:
    if not isinstance(value, str):
        err(errors, "username", "invalid_type", "Username must be a string.")
        return None

    raw = value
    name = unicodedata.normalize("NFKC", raw.strip()).casefold()
    skel = skeletonize(name)

    if raw != raw.strip():
        err(errors, "username", "outer_whitespace", "Username cannot start or end with whitespace.")
    if len(name) < 3 or len(name) > 32:
        err(errors, "username", "bad_length", "Username must be 3-32 characters.")
    if has_unsafe_unicode(raw) or any(ord(ch) > 127 for ch in raw):
        err(errors, "username", "unicode_blocked", "Username must use ASCII characters to prevent homoglyph abuse.")
    if not USERNAME_RE.fullmatch(name):
        err(errors, "username", "bad_characters", "Use lowercase letters, numbers, dots, hyphens, or underscores only.")
    if re.search(r"[_.-]{2,}", name):
        err(errors, "username", "repeated_punctuation", "Username cannot contain repeated punctuation.")
    if name in RESERVED_USERNAMES or skel in RESERVED_USERNAMES:
        err(errors, "username", "reserved", "Username is reserved.")
    if any(term and term in skel for term in BANNED_TERMS):
        err(errors, "username", "blocked_term", "Username contains blocked terms.")
    if "@" in name or URL_RE.search(name):
        err(errors, "username", "looks_like_contact", "Username cannot be an email address or URL.")

    return {"username": name, "username_skeleton": skel}


def estimate_entropy_bits(password: str) -> float:
    pool = 0
    pool += 26 if re.search(r"[a-z]", password) else 0
    pool += 26 if re.search(r"[A-Z]", password) else 0
    pool += 10 if re.search(r"\d", password) else 0
    pool += 33 if re.search(r"[^A-Za-z0-9\s]", password) else 0
    pool += 40 if any(ord(ch) > 127 for ch in password) else 0
    return len(password) * math.log2(max(pool, 2))


def breached_password(password: str) -> tuple[bool, bool]:
    if not ENABLE_HIBP:
        return False, True
    digest = hashlib.sha1(password.encode("utf-8")).hexdigest().upper()
    prefix, suffix = digest[:5], digest[5:]
    try:
        req = urllib.request.Request(
            f"https://api.pwnedpasswords.com/range/{prefix}",
            headers={"User-Agent": "registration-validator", "Add-Padding": "true"},
        )
        with urllib.request.urlopen(req, timeout=2.5) as resp:
            for line in resp.read().decode("utf-8", "ignore").splitlines():
                found, *_ = line.split(":")
                if hmac.compare_digest(found, suffix):
                    return True, True
        return False, True
    except Exception:
        return False, False


def validate_password(value: Any, clean: dict[str, str], errors: list[dict[str, str]]) -> str | None:
    if not isinstance(value, str):
        err(errors, "password", "invalid_type", "Password must be a string.")
        return None

    password = value
    normalized = unicodedata.normalize("NFKC", password)
    lower = normalized.casefold()

    if len(password) < 12:
        err(errors, "password", "too_short", "Password must be at least 12 characters.")
    if len(password) > MAX_PASSWORD_CHARS or len(password.encode("utf-8")) > MAX_PASSWORD_BYTES:
        err(errors, "password", "too_long", "Password is too long.")
    if has_unsafe_unicode(password) or "\x00" in password:
        err(errors, "password", "unsafe_characters", "Password contains unsafe control characters.")
    if password != password.strip():
        err(errors, "password", "outer_whitespace", "Password cannot start or end with whitespace.")

    classes = sum(bool(re.search(p, password)) for p in [r"[a-z]", r"[A-Z]", r"\d", r"[^A-Za-z0-9\s]"])
    if classes < 3:
        err(errors, "password", "insufficient_complexity", "Use at least 3 of: lowercase, uppercase, number, symbol.")
    if estimate_entropy_bits(password) < 50:
        err(errors, "password", "low_entropy", "Password entropy is too low.")
    if lower in COMMON_PASSWORDS or re.sub(r"[^a-z0-9]", "", lower) in COMMON_PASSWORDS:
        err(errors, "password", "common_password", "Password is too common.")
    if re.search(r"(.)\1{3,}", normalized):
        err(errors, "password", "repeated_characters", "Password has too many repeated characters.")

    sequences = ["abcdefghijklmnopqrstuvwxyz", "zyxwvutsrqponmlkjihgfedcba", "0123456789", "9876543210", "qwertyuiop", "asdfghjkl", "zxcvbnm"]
    if any(seq[i:i + 5] in lower for seq in sequences for i in range(len(seq) - 4)):
        err(errors, "password", "sequence", "Password contains an obvious sequence.")

    identifiers = [clean.get("username", ""), clean.get("email", "").split("@")[0], clean.get("display_name_plain", "")]
    for ident in filter(lambda x: len(x) >= 4, identifiers):
        ident = ident.casefold()
        if hmac.compare_digest(lower, ident) or ident in lower:
            err(errors, "password", "similar_to_identity", "Password cannot contain your username, email, or display name.")
            break

    pwned, checked = breached_password(password)
    if pwned:
        err(errors, "password", "breached", "Password appears in a known breach corpus.")
    if REQUIRE_HIBP and not checked:
        err(errors, "password", "breach_check_unavailable", "Password breach check is temporarily unavailable.")

    return password


def validate_display_name(value: Any, errors: list[dict[str, str]]) -> dict[str, str] | None:
    if not isinstance(value, str):
