def validate_payload(payload: Any) -> tuple[dict[str, str], list[dict[str, str]]]:
    errors: list[dict[str, str]] = []
    clean: dict[str, str] = {}

    if not isinstance(payload, dict):
        return clean, [{"field": "body", "code": "invalid_type", "message": "Request body must be a JSON object."}]

    allowed = {"email", "username", "password", "display_name"}
    for field in allowed:
        if field not in payload:
            err(errors, field, "required", f"{field} is required.")
    for field in sorted(set(payload) - allowed):
        err(errors, field, "unknown_field", "Unknown field is not allowed.")

